<?php $adminTitle='Edit Course'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; $course=get_course($pdo,(int)($_GET['id']??0)); if(!$course) exit('Course not found'); if($_SERVER['REQUEST_METHOD']==='POST' && verify_csrf($_POST['csrf_token']??null)){ $slug=trim($_POST['slug']) ?: slugify($_POST['title']); $stmt=$pdo->prepare('UPDATE lms_courses SET category_id=:cat,title=:title,slug=:slug,short_description=:short,full_description=:full,level=:level,duration=:duration,instructor=:instructor,thumbnail_image=:thumb,price_type=:ptype,price=:price,status=:status,learning_outcomes=:outcomes,requirements=:req,target_audience=:aud WHERE id=:id'); $stmt->execute([':cat'=>(int)$_POST['category_id'],':title'=>trim($_POST['title']),':slug'=>$slug,':short'=>trim($_POST['short_description']),':full'=>trim($_POST['full_description']),':level'=>$_POST['level'],':duration'=>trim($_POST['duration']),':instructor'=>trim($_POST['instructor']),':thumb'=>trim($_POST['thumbnail_image']),':ptype'=>$_POST['price_type'],':price'=>(float)$_POST['price'],':status'=>$_POST['status'],':outcomes'=>trim($_POST['learning_outcomes']),':req'=>trim($_POST['requirements']),':aud'=>trim($_POST['target_audience']),':id'=>(int)$course['id']]); header('Location: lms-courses.php'); exit; } ?><h1>Edit Course</h1><?php include __DIR__.'/_lms-course-form.php'; include __DIR__.'/../includes/admin-footer.php'; ?>